<?php declare(strict_types=1); $title=($editing?'Árszabály szerkesztése':'Új árszabály').' – A Bata'; require __DIR__.'/_layout_start.php'; $e=static fn(mixed $v):string=>htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8'); $action=$editing?'/admin/pricing/'.(int)$rule['id']:'/admin/pricing'; $weekdays=$rule['applicable_weekdays']??''; if(is_string($weekdays)&&str_starts_with($weekdays,'[')){ $decoded=json_decode($weekdays,true); $weekdays=is_array($decoded)?implode(',',$decoded):''; } ?>
